  ('elementary-f29af906-moex-00150', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關建物第一次測量，依地籍測量實施規則規定，一棟建物跨越二個以上登記機關轄區者，由何登記機關 受理測量，編列建號？', '["建築基地範圍內任一登記機關皆可", "該建物門牌所在地之登記機關", "該建物坐落基地面積較大地段之登記機關", "與該建物位置距離較近之登記機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00151', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關公務員法律義務，下列敘述何者錯誤？', '["公務員於在職期間不得經營商業或投機事業", "公務員於離職後3年內，不得擔任與其離職前5年內之職務直接相關之營利事業董事、監察人、經理、 執行業務之股東或顧問", "公務員對於長官在監督範圍內之命令，有服從之義務。如認為該命令違法，應負報告之義務；該管長官 如認其命令並未違法，而仍以口頭命令下達時，公務人員即應服從", "公務員對於公務上所辦事件，不得收受任何餽贈"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00152', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '針對地籍圖重測後，地政事務所依照重測結果辦竣土地標示變更登記後，發現原重測結果錯誤。關於其更 正之辦理，下列敘述何者正確？', '["更正重測成果，再更正土地標示登記", "逕更正土地標示登記，無須更正重測成果", "只須更正重測成果", "僅得由所有權人申請更正重測結果與土地標示登記，不得依職權辦理更正"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00153', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '若信託以遺囑為之者，依土地登記規則第126條之規定，下列敘述何者錯誤？', '["於遺囑另指定遺囑執行人時，應於辦畢遺囑執行人及繼承登記後，由遺囑執行人會同受託人申請信託登記", "無繼承人時，由受託人直接依遺囑申請信託登記", "信託登記應由繼承人辦理繼承登記後，會同受託人申請之", "繼承人有無不明時，於辦畢遺產管理人登記後，由遺產管理人會同受託人申請信託登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00154', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '因登記錯誤、遺漏或虛偽致受損害者，由地政機關負損害賠償責任。但下列何種情形不在此限？', '["地政機關證明其原因應歸責於第三人之詐術時", "地政機關證明其原因應歸責於受害人時", "地政機關證明其原因應不可歸責於登記人員時", "地政機關證明其原因應不可歸責於政府機關時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00155', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依地籍清理條例規定，主管機關為清查權利內容不完整或與現行法令規定不符之地籍登記，經釐清權利內 容及權屬後，應重新辦理登記；其未能釐清權利內容及權屬者，應如何處理？', '["逕為國有之登記", "徵收並予補償之", "法院拍賣之", "標售之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
