  ('elementary-f29af906-moex-00157', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地登記規則第118條規定，土地總登記後，因主張時效完成申請不動產役權登記，經登記機關審查證 明無誤應即公告，此一公告期間為幾日？', '["30日", "60日", "90日", "180日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
